// Topic format:
// <room>/data/<field>

var parts = msg.topic.split("/");

var room = parts[0];
var field = parts[2];

// Build field name from topic
var influxField = "data_" + parts[2];

const stringFields = ["ac"];
const intFields = [
    "active",
    "alert",
    "co2",
    "human",
    "led",
    "lux",
    "projector"
];
const floatFields = ["temp"];

var value;

if (stringFields.includes(field)) {
    value = String(msg.payload);
}
else if (intFields.includes(field)) {
    value = parseInt(msg.payload, 10);

    if (isNaN(value)) return null;

    // VERY IMPORTANT
    value = value.toString() + "i";
}
else if (floatFields.includes(field)) {
    value = parseFloat(msg.payload);

    if (isNaN(value)) return null;
}
else {
    node.warn("Unknown field: " + field);
    return null;
}

msg.payload = [
    {
        [field]: value
    },
    {
        room: room
    }
];

return msg;

let row = msg.payload;

msg.topic =

    row.room +
    "/control/" +
    row._field;

msg.payload = String(row._value);

return msg;

let row = msg.payload;

msg.topic =

    row.room +
    "/control/schedule";

msg.payload = String(row._value);

return msg;

const days = [
    "Sunday",
    "Monday",
    "Tuesday",
    "Wednesday",
    "Thursday",
    "Friday",
    "Saturday"
];

msg.payload = days[new Date().getDay()];
return msg;

let val = String(msg.payload);
if (val.length === 8) {
    let power = parseInt(val.substring(0, 2), 10) === 1;
    let temp = parseInt(val.substring(2, 4), 10);
    return [ { payload: power }, { payload: temp } ];
} else if (val.length === 3) {
    let power = parseInt(val.substring(0, 1), 10) === 1;
    let temp = parseInt(val.substring(1, 3), 10);
    return [ { payload: power }, { payload: temp } ];
}
return null;

// Extract the raw status text from the node
let mqttState = msg.status.text;

// Map the text to integers
if (mqttState === "node-red:common.status.connected") {
    msg.payload = 2; 
} else if (mqttState === "node-red:common.status.connecting") {
    msg.payload = 1;
} else {
    // This catches "disconnected", "error", or any other failure state
    msg.payload = 0; 
}

return msg;

// Extract the raw status text from the node
let mqttState = String(msg.payload);

// Map the text to integers
if (mqttState === "Online" || mqttState === "1") {
    msg.payload = 1; 
    flow.set("mqttCondition", 1);
} else {
    // This catches "disconnected", "error", or any other failure state
    msg.payload = 0; 
    flow.set("mqttCondition", 0);
}

return msg;

let ac_state ;
let ac_temp ;

flow.set (msg.topic, msg.payload);
ac_temp = flow.get("hvac_temp")||18;
ac_state = flow.get("hvac_state")||false;

let stateInt = ac_state ? 1 : 0;

let pp = stateInt === 1 ? "01" : "00";
let tt = String(ac_temp).padStart(2, '0');
let ff = "00";
let ss = "00";
msg.payload = `${pp}${tt}${ff}${ss}`;

return msg;

// Get the field name from topic (e.g. "temp", "co2", "lux", "human", etc.)
let parts = msg.topic.split("/");
let field = parts[parts.length - 1];

// Retrieve existing telemetry object from flow context, or initialize it
let telemetry = flow.get("telemetry") || {
    temp1: 0, temp2: 0, temp3: 0, temp4: 0,
    co: 0,
    humid1: 0, humid2: 0, humid3: 0, humid4: 0,
    lux1: 0, lux2: 0, lux3: 0, lux4: 0,
    luxProjector: 0,
    luxOut: 0,
    isOccupied: 0,
    tempAvg: 0,
    humAvg: 0,
    luxAvg: 0
};

let val = msg.payload;

if (field === "temp") {
    let t = parseFloat(val) || 0;
    telemetry.temp1 = t;
    telemetry.temp2 = t;
    telemetry.temp3 = t;
    telemetry.temp4 = t;
    telemetry.tempAvg = t;
} else if (field === "co2") {
    // Map CO2 to the dashboard's CO (co) field
    telemetry.co = parseFloat(val) || 0;
} else if (field === "lux") {
    let l = parseInt(val, 10) || 0;
    telemetry.lux1 = l;
    telemetry.lux2 = l;
    telemetry.lux3 = l;
    telemetry.lux4 = l;
    telemetry.luxAvg = l;
} else if (field === "human") {
    telemetry.isOccupied = (parseInt(val, 10) === 1) ? 1 : 0;
}

// Store the updated telemetry back
flow.set("telemetry", telemetry);

// Pass the telemetry payload to the dashboard widgets
msg.payload = telemetry;
return msg;

// 1. Fetch the physical reality from the main telemetry vault
let currentLux = flow.get("currentProjectorLux") || 0;
let targetState = flow.get("projectorTargetState");
let threshold = 300;

let msgLed = {};
let msgUnlock = { enabled: true,}; 

if (targetState === 1)
{
    if (currentLux >= threshold) 
    {
        msgLed.payload = 2;
        flow.set("projectorCondition", 1);
        msgUnlock.payload = 1; 
    } 
    else 
    {
        msgLed.payload = 3;
        flow.set("projectorCondition", 0);
        msgUnlock.payload = 0;
    }
}
else
{
    if (currentLux<threshold)
    {
        msgLed.payload = 0;
        flow.set("projectorCondition", 1);
        msgUnlock.payload = 0;
    }
    else
    {
        msgLed.payload = 3;
        flow.set("projectorCondition", 0);
        msgUnlock.payload = 1;
    }
}

flow.set("projectorBooting", false);
flow.set("blockEchoProjector", true);

return [msgLed, msgUnlock];

let currentTemp = msg.payload.tempAvg;
let acTemp = flow.get("hvac_temp") || 18;
let acState = flow.get("hvac_state")||false;

let monitorStartTime = context.get("monitorStartTime");
let monitorStartTemp = context.get("monitorStartTemp");

let msgLed = {};

if (acState === false)
{
    context.set("monitorStartTime", null);
    context.set("monitorStartTemp", null);

    msgLed.payload = 0;
    flow.set("tempCondition", 1);
    return msgLed;
}

if (currentTemp <= (acTemp + 1.0))
{
    context.set("monitorStartTime", null);
    context.set("monitorStartTemp", null);
    msgLed.payload = 2;
    flow.set("tempCondition", 1);
    return msgLed;
}
if (monitorStartTime == null)
{
    context.set("monitorStartTime", Date.now());
    context.set("montiroStartTemp", currentTemp);

    msgLed.payload = 2;
    flow.set("tempCondition", 1);
    return msgLed;
}

let timeElapsed = Date.now()-monitorStartTime;
let timer = 90000;

if (timeElapsed >= timer)
{
    if (currentTemp<= (monitorStartTemp - 0.5) || currentTemp <= 20.0)
    {
        context.set("monitorStartTime", Date.now());
        context.set("montiroStartTemp", currentTemp);
        msgLed.payload = 2;
        flow.set("tempCondition", 1);
    }
    else
    {
        msgLed.payload = 1;
        flow.set("tempCondition", 0);
    }
}
else
{
    msgLed.payload = 2;
    flow.set("tempCondition", 1);
}
return msgLed;

if (flow.get("blockEchoProjector") === true)
{
    flow.set("blockEchoProjector", false);
    return null;
}

if (flow.get("projectorBooting") === true) {
    return null;
}

flow.set("projectorBooting", true);
flow.set("projectorTargetState", msg.payload);

// 3. Prepare the Output Messages
// Output 1: Tell the LED to turn Orange (Value 1)
let msgLed = { payload: 1 };

// Output 2: Tell the Node-RED Dashboard to physically lock/grey out the button
let msgLock = { enabled: false };

// Output 3: The actual command to send to the ESP32 and the Delay Node
let msgCommand = {payload: msg.payload}; // Assuming 1 is your Modbus ON command

// 4. Route the messages out of the 3 specific ports
return [msgLed, msgLock, msgCommand];

if (msg.topic === "lamp1" && msg.payload === flow.get("lamp1")) return null;
if (msg.topic === "lamp2" && msg.payload === flow.get("lamp2")) return null; 
if (msg.topic === "lamp3" && msg.payload === flow.get("lamp3")) return null;
if (msg.topic === "lamp4" && msg.payload === flow.get("lamp4")) return null;
if (msg.topic === "main_lamp" && msg.payload === flow.get("main_lamp_state")) return null;

let l1 = flow.get('lamp1') || 0;
let l2 = flow.get('lamp2') || 0;
let l3 = flow.get('lamp3') || 0;
let l4 = flow.get('lamp4') || 0;

let mainStateCommand = null;
let syncL1 = null, syncL2 = null, syncL3 = null, syncL4 = null;

if (msg.topic === "app_array") 
{
    let str = String(msg.payload);
    if (str.length !==4) return null;

    l1 = parseInt(str.charAt(0), 10);
    l2 = parseInt(str.charAt(1), 10);
    l3 = parseInt(str.charAt(2), 10);
    l4 = parseInt(str.charAt(3), 10);

    flow.set('lamp1', l1);
    flow.set('lamp2', l2);
    flow.set('lamp3', l3);
    flow.set('lamp4', l4);

    syncL1 = {payload: l1};
    syncL2 = {payload: l2};
    syncL3 = {payload: l3};
    syncL4 = {payload: l4};

} 
else if (msg.topic === "main_lamp")
{
    flow.set ('main_lamp_state', msg.payload);
    l1 = l2 = l3 = l4 = msg.payload;

    flow.set('lamp1', l1);
    flow.set('lamp2', l2);
    flow.set('lamp3', l3);
    flow.set('lamp4', l4); 

    syncL1 = { payload: l1 };
    syncL2 = { payload: l2 };
    syncL3 = { payload: l3 };
    syncL4 = { payload: l4 };

}
else 
{
    flow.set (msg.topic, msg.payload);

    l1 = flow.get('lamp1') || 0;
    l2 = flow.get('lamp2') || 0;
    l3 = flow.get('lamp3') || 0;
    l4 = flow.get('lamp4') || 0;
}

if (l1 === 0 && l2 === 0 && l3 === 0 && l4 === 0) {
    mainStateCommand = { payload: 0 };
} else if (l1 === 1 && l2 === 1 && l3 === 1 && l4 === 1) {
    mainStateCommand = { payload: 1 };
}
let binaryTelemetry = {payload: (l1 === 0 && l2 === 0 && l3 === 0 && l4 === 0) ? 0 : 1};

return [mainStateCommand, binaryTelemetry, syncL1, syncL2, syncL3, syncL4];

let str = String(msg.payload);
if (str.length === 4) {
    msg.topic = "app_array";
} else {
    let val = (str === "1" || str === "true" || str === "on") ? 1 : 0;
    msg.payload = val;
    msg.topic = "main_lamp";
}
return msg;

let luxAvg = msg.payload.luxAvg;

let threshold = parseInt(flow.get("lampThreshold"), 10) || 0;
let l1 = parseInt (flow.get("lamp1"),10) || 0;
let l2 = parseInt (flow.get("lamp2"),10)  || 0;
let l3 = parseInt (flow.get("lamp3"),10)  || 0;
let l4 = parseInt (flow.get("lamp4"),10)  || 0;

let msgLed = {};
if (l1 === 0 && l2 === 0 && l3 === 0 && l4 ===0)
{
    msgLed.payload = 0;
    flow.set("lampCondition", 1);
    return msgLed;
}

if (luxAvg === undefined || isNaN(luxAvg))
{
    return null;
}

if (luxAvg < threshold)
{
    msgLed.payload = 1;
    flow.set("lampCondition", 0);

}
else 
{
    msgLed.payload = 2;
    flow.set("lampCondition", 1);

}
return msgLed

let tempCondition = parseInt(flow.get("tempCondition"), 10) || 0;
let lampCondition = parseInt(flow.get("lampCondition"), 10) || 0;
let projectorCondition = parseInt(flow.get("projectorCondition"), 10) || 0;
let mqttCondition = parseInt(flow.get("mqttCondition"), 10) || 0;

let msgLed = {};
if (mqttCondition === 0)
{
    msgLed.payload = 0;
}
else if (tempCondition === 1 && lampCondition === 1 && projectorCondition === 1 )
{
    msgLed.payload = 2;
}
else
{
    msgLed.payload = 1;
}
return msgLed;
